#!/usr/bin/env python3
# Piece 1c-cost (dream-os) — surface the per-turn cost (the price thesis, live).
#
# dream-os already has calculateCost() in models.js (Haiku $1/M in, $5/M out).
# This wires it through the dual-soul loop:
#   * kriyaTurn tallies its tokens and reports usage up
#   * myraLoop sums Myra's streams + Kriya's sub-turns, calls calculateCost,
#     returns inputTokens/outputTokens/costUsd/costInr
#   * chat.js copies cost + tokens into the streamed `done` beat (and the JSON
#     path + messages persistence already read these fields)
#
# Overwrites kriyaTurn.js + myraLoop.js; patches chat.js done beat. Anchor-guarded.

import base64, os, sys
ROOT=os.getcwd()
PAYLOADS={
    'src/agent/kriyaTurn.js': '',
    'src/agent/myraLoop.js': '',
}
DONE_OLD = """      const donePayload = { type: 'done', tool_calls: toolCallNames };
      if (result.refresh)  donePayload.refresh  = true;"""
DONE_NEW = """      const donePayload = { type: 'done', tool_calls: toolCallNames };
      if (result.costInr  != null) donePayload.cost_inr     = result.costInr;
      if (result.costUsd  != null) donePayload.cost_usd     = result.costUsd;
      if (result.inputTokens  != null) donePayload.input_tokens  = result.inputTokens;
      if (result.outputTokens != null) donePayload.output_tokens = result.outputTokens;
      if (result.refresh)  donePayload.refresh  = true;"""

def main():
    if not os.path.isdir(os.path.join(ROOT,"src","agent")):
        print("ERROR: run from dream-os repo root."); sys.exit(1)
    for rel,b64 in PAYLOADS.items():
        open(os.path.join(ROOT,rel),"wb").write(base64.b64decode(b64)); print(f"OK: overwrote {rel}")
    # patch chat.js done beat
    cp=os.path.join(ROOT,"src","api","vendor","chat.js")
    s=open(cp,encoding="utf-8").read()
    if "donePayload.cost_inr" in s:
        print("SKIP: chat.js done beat already carries cost.")
    elif DONE_OLD in s:
        open(cp,"w",encoding="utf-8").write(s.replace(DONE_OLD,DONE_NEW,1))
        print("OK: chat.js done beat now carries cost_inr/cost_usd/tokens.")
    else:
        print("SKIP: done-beat anchor not found — add cost fields to donePayload by hand.")
    print("\nPiece 1c-cost written. Per-turn cost now rides the done beat.")
if __name__=="__main__": main()
